124→/**
125→ * Get detailed reactions breakdown for a post.
126→ */
127→export const getPostReactionsService = async (journalId) => {
128→    if (!journalId) {
129→        throw { status: 400, error: 'journalId is required' };
130→    }
131→
132→    const { data, error } = await supabase.rpc('get_post_reactions', {
133→        p_journal_id: journalId,
134→    });
135→
136→    if (error) {
137→        console.error('error getting post reactions:', error.message);
138→        throw { status: 500, error: 'failed to get reactions' };
139→    }
140→
141→    return { reactions: data || [] };
142→};
